/* eslint-disable @rushstack/no-new-null */
import { EventEmitter } from 'eventemitter3';

type AbstractWebSocket = WebSocket;

export class WebSocketImpl implements AbstractWebSocket {
    static CONNECTING = 0 as const;
    static OPEN = 1 as const;
    static CLOSING = 2 as const;
    static CLOSED = 3 as const;

    CONNECTING = 0 as const;
    OPEN = 1 as const;
    CLOSING = 2 as const;
    CLOSED = 3 as const;

    binaryType: BinaryType = 'arraybuffer';
    bufferedAmount: number = 65535;
    extensions: string = '';
    onclose: ((this: WebSocket, ev: CloseEvent) => unknown) | null = null;
    onerror: ((this: WebSocket, ev: Event) => unknown) | null = null;
    onmessage: ((this: WebSocket, ev: MessageEvent<unknown>) => unknown) | null = null;
    onopen: ((this: WebSocket, ev: Event) => unknown) | null = null;
    protocol: string = '';
    readyState: number = this.CONNECTING;
    url: string = '';

    port: MessagePort;

    private eventEmitter = new EventEmitter();

    constructor(_url: string | URL) {
        // @ts-expect-error
        const worker = new SharedWorker(new URL('@root/workers/web-socket/index.ts', import.meta.url));

        const port = worker.port;

        this.port = port;

        port.addEventListener('message', ev => {
            this.eventEmitter.emit('message', {
                data: ev.data,
            });
        });

        port.addEventListener('messageerror', () => {
            this.eventEmitter.emit('error');
        });
    }

    private connect() {
        if (this.readyState !== this.CONNECTING) {
            return;
        }
        this.port.start();
        this.readyState = this.OPEN;
        self.setTimeout(() => this.eventEmitter.emit('open'), 0);
    }

    close(code?: number, reason?: string): void;
    close(code?: number, reason?: string): void;
    close(_code?: unknown, _reason?: unknown): void {
        this.readyState = this.CLOSING;
        this.port.close();
        this.readyState = this.CLOSED;
        self.setTimeout(() => this.eventEmitter.emit('close'), 0);
    }

    send(data: string | ArrayBufferLike | Blob | ArrayBufferView): void;
    send(data: string | ArrayBufferLike | Blob | ArrayBufferView): void;
    send(data: unknown): void {
        this.connect();
        this.port.postMessage(data);
    }

    addEventListener<K extends keyof WebSocketEventMap>(
        type: K,
        listener: (this: WebSocket, ev: WebSocketEventMap[K]) => unknown,
        options?: boolean | AddEventListenerOptions
    ): void;
    addEventListener(type: string, listener: EventListenerOrEventListenerObject, options?: boolean | AddEventListenerOptions): void;
    addEventListener<K extends keyof WebSocketEventMap>(
        type: K,
        listener: (this: WebSocket, ev: WebSocketEventMap[K]) => unknown,
        options?: boolean | AddEventListenerOptions
    ): void;
    addEventListener(type: string, listener: EventListenerOrEventListenerObject, options?: boolean | AddEventListenerOptions): void;
    addEventListener(type: string, listener: unknown, _options?: unknown): void {
        this.connect();
        if (typeof listener === 'function') {
            // @ts-ignore
